import java.util.ArrayList;

class Main {
  public static void main(String[] args) {
    // Create a new, completely empty ArrayList
    ArrayList<String> cart = new ArrayList<String>();

    // Add items (The array magically stretches!)
    cart.add("Apple");
    cart.add("Banana");

    // Remove items (The array shrinks back!)
    cart.remove("Apple");

    System.out.println(cart);
  }
}
